messages.content:
RISKS:
[
 {
  "riskId": "risk.demand-discontinuity.prelet-lockout-year1-contestability",
  "title": "83% pre-let pipeline plus long-lead electrical frameworks leave almost no contestable Year-1 PDU orders",
  "claim": "The obtainableFactor's own cross-check assumes DC electrical gear is locked 12–24 months before fit-out, which keeps a ≤2% Year-1 share plausible. But the FLAP-D development pipeline is 83% pre-let at a record-low 6.3% vacancy — the 2026–27 builds a new entrant would sell into had their electrical bill-of-materials specified inside framework agreements signed at pre-let, i.e. in 2023–24. The venture's first 12 months open onto a market where the visible demand is real but already awarded: what remains contestable is churn and expansion inside operating halls, a fraction of the 1% anchor. The YAM is not conservative; it is counting orders that were signed before the company existed in the market.",
  "falsifier": "Three or more CE colocation fit-outs commissioning in 2026–27 running open rack-PDU bake-offs (multi-bidder, no incumbent framework) during the venture's first two quarters."
 },
 {
  "riskId": "risk.demand-discontinuity.frankfurt-grid-queue-de-slip",
  "title": "A single metro's 24–36-month grid queue gates ~37% of the CE TAM's Year-1 flow",
  "claim": "Germany is 0.50 of the base and Frankfurt hosts ~75% of German IT capacity — so roughly 37% of the venture's TAM routes through one metro's grid interconnection queue, where waits now run 24–36 months and vacancy is 2.2%. The model treats DE as a diversified half of the market; in the first-12-months window it is really a bet that Frankfurt's 542 MW under construction energizes on schedule. If 2026 energizations slip right — grid queue, plus EnEfG efficiency/heat-reuse compliance adding commissioning friction — the fit-outs that would generate the venture's largest tranche of Year-1 PDU purchase orders move to 2027–28 while the 9% trend stays intact on paper.",
  "falsifier": "TenneT/regional grid operator commitments (or JLL Frankfurt prints) showing Frankfurt live IT load stepping up by >100 MW within the venture's Year-1, i.e. the 542 MW under construction energizing on schedule."
 },
 {
  "riskId": "risk.demand-discontinuity.nl-grid-freeze-share-erosion",
  "title": "The Netherlands' 0.28 slice is legally and electrically frozen for the entire Year-1 window",
  "claim": "geo.NL = 0.28 is one of the best-triangulated nodes in the ledger — Statista and the DDA agree within 3%. But both measure installed stock, and the venture sells into flow: new fit-outs where a new vendor can be designed in. In NL that flow is administratively shut for the whole first-12-months window: a national decree bans new hyperscale builds outside two municipalities, Amsterdam's draft zoning plan caps connections at 350 MVA until 2030, and distribution firms say no power is available until 2030 — with Amsterdam holding ~70% of national colo. What remains in NL is replacement demand inside operating halls, the most incumbent-locked business there is. Nearly a third of the funnel is a stock share masquerading as an addressable flow.",
  "falsifier": "Liander/Stedin announcing material new data-center grid allocations before 2030, or the DDA reporting >80 MW of newly commissioned Dutch colocation capacity within the venture's Year-1."
 },
 {
  "riskId": "risk.demand-discontinuity.ce-hyperscale-flow-mirage",
  "title": "Year-1 hyperscale demand lands in Ireland, Sweden and Belgium — the 0.44 CE slice is a global split painted on the wrong map",
  "claim": "seg.hyperscale rescales Synergy's global 44–48% capacity share onto Central Europe via a flat 0.91 carve-out. But ~60% of Europe's operational hyperscale self-build capacity sits in Ireland, the Netherlands, Sweden and Belgium — three of the four outside CE-7 entirely, and the fourth banned from new hyperscale construction. The 2026 self-build wave (4.2 GW, +24% YoY) will follow existing land banks and secured grid positions, i.e. mostly outside the venture's geographic scope, while inside CE-7 hyperscalers consume capacity as colo pre-lets procured through global frameworks. The model's largest segment is substantially a demand flow the venture cannot geographically reach in Year 1, and the 'sell to large operators first' strategy is aimed at it.",
  "falsifier": "A Europe-scoped capacity split (CBRE, Synergy custom cut, or DC Byte) showing CE-7 hyperscale-operated share at or above ~0.40, or two-plus announced 2026 CE-7 hyperscale self-build campuses breaking ground outside the NL exception zones."
 },
 {
  "riskId": "risk.demand-discontinuity.construction-plateau-lumpy-year1",
  "title": "Construction has plateaued while the pipeline balloons: Year-1 opens onto a digestion trough the 9% trend averages away",
  "claim": "EMEA capacity under construction has plateaued at ~2.5 GW even as the development pipeline swelled 25% to nearly 15 GW — projects are stacking in planning, not converting to builds, because grid, permits and capex phasing bind. PDU purchase orders follow construction fit-out, not pipeline announcements. And with public cloud providers taking 61% of 2025 EMEA take-up, three or four hyperscaler capex committees synchronize the whole cycle: if 2026 is an AI-capex digestion year, CE fit-out starts pause for 2–4 quarters exactly inside the venture's window while the 2030 CAGR remains intact on paper. The 1%-of-SAM Year-1 anchor implicitly assumes an on-trend year; the conversion data says the window may be a below-trend one.",
  "falsifier": "Cushman & Wakefield / JLL H1-2026 EMEA prints showing under-construction capacity breaking materially above ~2.5 GW with CE construction starts rising, or hyperscaler earnings guidance re-accelerating European data-center capex for 2026."
 }
]

Emit JSON: { items: [{riskId, queries: [{query, kind: confirming|falsifying|base-rate}]}] } — 3 queries per risk.
